import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/button/src/button.component.js';
const tagName = 'made-button';
Component.define('made-button');
/**
 * @summary Buttons represent actions that are available to the user.
 * @documentation '../../components/button/stories/button.mdx'
 *
 * @slot - The button's label.
 * @slot start - Used to place content before button text. Typically used for icons.
 * @slot end - Used to place content after button text. Typically used for icons.
 *
 * @csspart base - The component's base wrapper.
 * @csspart start - The container that wraps the start slot.
 * @csspart label - The button's label.
 * @csspart end - The container that wraps the end slot.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeButton'
});
export default reactWrapper;
